from flask import Flask, redirect, url_for, session, request
import requests
import jwt
import os
import secrets

app = Flask(__name__)
app.secret_key = os.urandom(24)

OIDC_CLIENT_ID = 'your_client_id'
OIDC_CLIENT_SECRET = 'your_client_secret'
OIDC_AUTHORIZATION_ENDPOINT = 'https://provider.com/authorize'
OIDC_TOKEN_ENDPOINT = 'https://provider.com/token'
OIDC_USERINFO_ENDPOINT = 'https://provider.com/userinfo'
OIDC_REDIRECT_URI = 'http://localhost:5000/callback'
OIDC_ISSUER = 'https://provider.com/'

def generate_nonce():
    return secrets.token_urlsafe(16)

@app.route('/')
def home():
    if 'user' in session:
        return f"Hello, {session['user']['name']}!"
    return 'Welcome! <a href="/login">Login</a>'

@app.route('/login')
def login():
    nonce = generate_nonce()
    session['nonce'] = nonce
    authorization_url = f"{OIDC_AUTHORIZATION_ENDPOINT}?response_type=code&client_id={OIDC_CLIENT_ID}&redirect_uri={OIDC_REDIRECT_URI}&scope=openid%20profile&nonce={nonce}"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    token_response = requests.post(OIDC_TOKEN_ENDPOINT, data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_REDIRECT_URI,
        'client_id': OIDC_CLIENT_ID,
        'client_secret': OIDC_CLIENT_SECRET
    }).json()

    id_token = token_response.get('id_token')
    decoded_id_token = jwt.decode(id_token, options={"verify_signature": False})

    if decoded_id_token.get('nonce') != session.pop('nonce', None):
        return 'Invalid nonce', 400

    session['user'] = {
        'name': decoded_id_token.get('name'),
        'email': decoded_id_token.get('email')
    }
    return redirect(url_for('home'))

if __name__ == '__main__':
    app.run(debug=True)